"use client";

import React, { ComponentProps } from "react";
import { motion, useAnimation } from "framer-motion";
import { ArrowRight } from "lucide-react";

type Props = ComponentProps<typeof motion.button> & {
  children: React.ReactNode;
};

const ExpandOnHoverButton = ({
  children,
  className = "",
  ...props
}: Props) => {
  const controls = useAnimation();

  return (
    <motion.button
      className={`group inline-flex items-center gap-2 px-6 py-3 text-sm font-semibold text-white bg-slate-900 rounded-full overflow-hidden transition-shadow hover:shadow-xl dark:bg-white dark:text-slate-900 ${className}`}
      onHoverStart={() => controls.start("visible")}
      onHoverEnd={() => controls.start("hidden")}
      {...props}
    >
      <span>{children}</span>

      <motion.div
        variants={{
          hidden: { opacity: 0, x: -10 },
          visible: { opacity: 1, x: 0 },
        }}
        initial="hidden"
        animate={controls}
        transition={{ duration: 0.2 }}
      >
        <ArrowRight className="w-4 h-4" />
      </motion.div>
    </motion.button>
  );
};

export default ExpandOnHoverButton;

